import{_ as s,o as a,c as l,ae as e}from"./chunks/framework.CL3pmU-5.js";const i="/ComputerNetwork/assets/%E8%BE%B9%E7%BC%98%E7%BD%91%E7%BB%9C.ZBFZZeLL.svg",u=JSON.parse('{"title":"1.2 网络边缘","description":"","frontmatter":{},"headers":[],"relativePath":"第一章/1.2 网络边缘.md","filePath":"第一章/1.2 网络边缘.md"}'),o={name:"第一章/1.2 网络边缘.md"};function r(n,t,p,_,c,m){return a(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="_1-2-网络边缘" tabindex="-1">1.2 网络边缘 <a class="header-anchor" href="#_1-2-网络边缘" aria-label="Permalink to &quot;1.2 网络边缘&quot;">​</a></h1><p>在上面一节中我们对互联网有了一个整体的认识，我们接下来将对分别从一下几个角度来认识网络</p><ul><li>网络边缘</li><li>网络核心</li></ul><p><img src="'+i+'" alt="网络"></p><p>这节我们先来说什么是网络边缘。</p><p>网络边缘又叫做：接入系统（access），边缘系统（edge）</p><p>接入网络的模式有两种：</p><ol><li><strong>CS模式</strong>（传统，即客户端服务器模式）</li><li><strong>P2P模式</strong>（point to point）</li></ol><details class="details custom-block"><summary>Details</summary><p><strong>P2P</strong> : 一个终端既可以当服务器也可以当客户端，代表有：迅雷... 当我们在迅雷下载东西的时候，我们自己也可能正在当服务器给别人提供信息。</p></details><h2 id="专业名词" tabindex="-1">专业名词 <a class="header-anchor" href="#专业名词" aria-label="Permalink to &quot;专业名词&quot;">​</a></h2><p><strong>面向连接服务</strong>：在端系统之间传输数据</p><p><strong>握手</strong>：在数据传输之前做好准备，两个通讯主机之间为连接建立状态</p><p><strong>TCP服务</strong>：</p><ul><li>可靠的，按顺序的传送数（确认和重传）</li><li>流量控制（发送方不会淹没接收方）</li><li>拥塞控制（当网络拥塞时候，发送方降低发送速率）</li></ul><details class="details custom-block"><summary>Details</summary><p>使用TCP的有：HTTP（web），FTP（文件传输），TeInet（远程登录），SMTP（email）</p></details><p><strong>无连接服务</strong></p><ul><li>无连接</li><li>不可靠数据传输</li><li>无流量控制</li><li>无拥塞控制</li></ul><details class="details custom-block"><summary>Details</summary><p>使用无连接服务的有，流媒体，远程会议，DNS，Internet电话。</p><p>为什么这些可以使用无连接服务呢？</p></details>',18)])])}const g=s(o,[["render",r]]);export{u as __pageData,g as default};
